function ClienteDashboard() {
  return (
    <div style={{ padding: "20px" }}>
      <h2>Panel de Cliente</h2>
      <p>Aquí verás tu historial de compras y productos recomendados.</p>
    </div>
  );
}

export default ClienteDashboard;
